rust-sqlx.query_fn:
pub async fn find_user(pool: &sqlx::PgPool, id: i32) -> Result<FindUserRow, sqlx::Error> {
    sqlx::query_as!(FindUserRow, "SELECT id, name, email FROM users WHERE id = $1", id)
        .fetch_one(pool)
        .await
}

rust-sqlx.row_struct:
#[derive(Debug, sqlx::FromRow)]
pub struct FindUserRow {
    pub id: i32,
    pub name: String,
    pub email: String,
}

